1	type Item = { type: string; enchantment?: number; cursed?: boolean; material?: string };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Damage = { itemType: string; amount: number };
4	type Incident = { cause: string; damages: Damage[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
8	type QuoteResult = { premium: number };
9	type ClaimResult = { payout: number; remainingCap: number };
10	type StepResult = QuoteResult | ClaimResult;
11	
12	const PROCESSING_FEE = 5;
13	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
14	const THREE_ALIKE_BLOCK_PREMIUM = 60;
15	
16	type ItemTypeSpec = { basePremium: number; insuranceValue: number; isComponent: boolean };
17	
18	const ITEM_TYPES: Record<string, ItemTypeSpec> = {
19	  // Whole items
20	  sword: { basePremium: 100, insuranceValue: 1000, isComponent: false },
21	  amulet: { basePremium: 60, insuranceValue: 600, isComponent: false },
22	  staff: { basePremium: 80, insuranceValue: 800, isComponent: false },
23	  potion: { basePremium: 40, insuranceValue: 400, isComponent: false },
24	  // Components (eligible for 3-alike block premium)
25	  rune: { basePremium: 25, insuranceValue: 250, isComponent: true },
26	  moonstone: { basePremium: 25, insuranceValue: 250, isComponent: true },
27	};
28	
29	const percentOf = (amount: number, percent: number): number => (amount * percent) / 100;
30	
31	const countByType = (items: Item[]): Map<string, number> =>
32	  items.reduce(
33	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
34	    new Map<string, number>(),
35	  );
36	
37	const basePremiumForGroup = (type: string, count: number): number => {
38	  const spec = ITEM_TYPES[type];
39	  if (spec.isComponent && count === 3) return THREE_ALIKE_BLOCK_PREMIUM;
40	  return count * spec.basePremium;
41	};
42	
43	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
44	const HIGH_ENCHANTMENT_THRESHOLD = 5;
45	const CURSE_SURCHARGE_PERCENT = 50;
46	
47	// Each surcharge rule receives the item and its base premium and returns
48	// the surcharge amount in gold (0 when the rule does not apply).
49	type ItemSurchargeRule = (item: Item, itemBase: number) => number;
50	
51	const ITEM_SURCHARGE_RULES: ItemSurchargeRule[] = [
52	  (item, itemBase) =>
53	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
54	      ? percentOf(itemBase, HIGH_ENCHANTMENT_SURCHARGE_PERCENT)
55	      : 0,
56	  (item, itemBase) =>
57	    item.cursed ? percentOf(itemBase, CURSE_SURCHARGE_PERCENT) : 0,
58	];
59	
60	const itemSurcharges = (item: Item): number => {
61	  const itemBase = ITEM_TYPES[item.type].basePremium;
62	  return ITEM_SURCHARGE_RULES.reduce((sum, rule) => sum + rule(item, itemBase), 0);
63	};
64	
65	const sumBy = <T>(items: T[], valueOf: (item: T) => number): number =>
66	  items.reduce((sum, item) => sum + valueOf(item), 0);
67	
68	const policyBasePremium = (items: Item[]): number =>
69	  sumBy(
70	    [...countByType(items)],
71	    ([type, count]) => basePremiumForGroup(type, count),
72	  );
73	
74	const itemSurchargesTotal = (items: Item[]): number => sumBy(items, itemSurcharges);
75	
76	const LOYALTY_DISCOUNT_PERCENT = 20;
77	const LOYALTY_MIN_YEARS = 2;
78	const FOLLOWUP_CONTRACT_DISCOUNT_PERCENT = 15;
79	
80	// Each policy adjustment receives the base premium and quote context and
81	// returns a signed amount in gold: positive for surcharges, negative for
82	// discounts, 0 when the rule does not apply.
83	type QuoteContext = { yearsWithMHPCO: number; priorQuoteCount: number };
84	type PolicyAdjustmentRule = (basePremium: number, context: QuoteContext) => number;
85	
86	const POLICY_ADJUSTMENT_RULES: PolicyAdjustmentRule[] = [
87	  (basePremium) => percentOf(basePremium, FIRST_INSURANCE_SURCHARGE_PERCENT),
88	  (basePremium, { yearsWithMHPCO }) =>
89	    yearsWithMHPCO >= LOYALTY_MIN_YEARS ? -percentOf(basePremium, LOYALTY_DISCOUNT_PERCENT) : 0,
90	  (basePremium, { priorQuoteCount }) =>
91	    priorQuoteCount > 0 ? -percentOf(basePremium, FOLLOWUP_CONTRACT_DISCOUNT_PERCENT) : 0,
92	];
93	
94	const policyAdjustmentsTotal = (basePremium: number, context: QuoteContext): number =>
95	  sumBy(POLICY_ADJUSTMENT_RULES, (rule) => rule(basePremium, context));
96	
97	const quotePremium = (items: Item[], context: QuoteContext): number => {
98	  const base = policyBasePremium(items);
99	  const beforeFee = base + policyAdjustmentsTotal(base, context) + itemSurchargesTotal(items);
100	  return Math.ceil(beforeFee) + PROCESSING_FEE;
101	};
102	
103	const DEDUCTIBLE_PER_DAMAGE = 100;
104	const CAP_MULTIPLIER = 2;
105	
106	const insuranceSum = (items: Item[]): number =>
107	  sumBy(items, (item) => ITEM_TYPES[item.type].insuranceValue);
108	
109	type Policy = { items: Item[]; remainingCap: number };
110	
111	const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
112	  const payout = sumBy(incident.damages, (damage) =>
113	    Math.max(0, damage.amount - DEDUCTIBLE_PER_DAMAGE),
114	  );
115	  policy.remainingCap -= payout;
116	  return { payout: Math.floor(payout), remainingCap: policy.remainingCap };
117	};
118	
119	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
120	  const yearsWithMHPCO = scenario.customer.yearsWithMHPCO;
121	  const policies: Policy[] = [];
122	  let priorQuoteCount = 0;
123	  const results: StepResult[] = scenario.steps.map((step) => {
124	    if (step.op === "quote") {
125	      const premium = quotePremium(step.items, { yearsWithMHPCO, priorQuoteCount });
126	      policies.push({ items: step.items, remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER });
127	      priorQuoteCount += 1;
128	      return { premium };
129	    }
130	    return processClaim(policies[step.policy], step.incident);
131	  });
132	  return { results };
133	};
