const insuranceSum = (items: Item[]): number =>
  sumBy(items, (item) => ITEM_TYPES[item.type].insuranceValue);

const policyCap = (items: Item[]): number => insuranceSum(items) * CAP_MULTIPLIER;

type Policy = { items: Item[]; remainingCap: number };

const damagePayout = (damage: Damage): number =>
  Math.max(0, damage.amount - DEDUCTIBLE_PER_DAMAGE);

const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
  const payout = sumBy(incident.damages, damagePayout);
  const remainingCap = policy.remainingCap - payout;
  policy.remainingCap = remainingCap;
  return { payout: Math.floor(payout), remainingCap };
};

export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
  const { yearsWithMHPCO } = scenario.customer;
  const policies: Policy[] = [];
  const results: StepResult[] = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const premium = quotePremium(step.items, {
        yearsWithMHPCO,
        priorQuoteCount: policies.length,
      });
      policies.push({ items: step.items, remainingCap: policyCap(step.items) });
      return { premium };
    }
    return processClaim(policies[step.policy], step.incident);
  });
  return { results };
};
